</head>
<body>
  <div class="chat-container">
    <div class="header"><div class="header-dot"></div>n8n Agent</div>
    <div class="messages" id="messages">
      <div class="message bot">Hello! I am your n8n assistant. You can type or use the 🎤 mic button to speak.</div>
    </div>
    <div class="status" id="status"></div>
    <form class="input-area" id="chat-form">
      <button type="button" id="mic-btn" title="Click to record">🎤</button>
      <input type="text" id="input" placeholder="Type or speak a message..." autocomplete="off" />
      <button type="submit" id="send-btn">Send</button>
    </form>
  </div>

  <!-- ── Approval Overlay ── -->
  <div id="approval-overlay">
    <div class="approval-box">
      <div class="approval-header">
        <span>⚠️</span> Action Requires Approval
      </div>

      <div class="approval-field">
        <div class="approval-label">Action</div>
        <div class="approval-value" id="ap-action">—</div>
      </div>

      <div class="approval-field">
        <div class="approval-label">Command</div>
        <div class="approval-command" id="ap-command">—</div>
      </div>

      <div class="approval-field">
        <div class="approval-label">Description</div>
        <div class="approval-value" id="ap-desc">—</div>
      </div>

      <div class="approval-field">
        <div class="approval-label">Risk</div>
        <div class="risk-badge" id="ap-risk">—</div>
      </div>

      <hr class="approval-divider">
      <div class="approval-question">Do you want to approve this action?</div>
      <div class="approval-buttons">
        <button type="button" class="btn-deny" onclick="submitApproval('denied')">✕ Deny</button>
        <button type="button" class="btn-approve" onclick="submitApproval('approved')">✓ Approve</button>
      </div>
      <div class="approval-sent" id="ap-sent" style="display:none">Sending response...</div>
    </div>
  </div>

  <script>
    const form = document.getElementById('chat-form');
    const input = document.getElementById('input');
    const messages = document.getElementById('messages');
    const sendBtn = document.getElementById('send-btn');
    const micBtn = document.getElementById('mic-btn');
    const status = document.getElementById('status');

    // ── API endpoints ─────────────────────────────
    const base = window.location.origin + '/webhook';
    const API_URL     = base + '/chat-response';
    const WHISPER_URL = base + '/whisper-proxy';
    const TTS_URL     = base + '/tts-proxy';

    let approvalPending = false;
    let currentResumeUrl = null;

    function showApprovalDialog(data) {
      approvalData = data;
      document.getElementById('ap-action').textContent = data.description || 'Command execution';
      document.getElementById('ap-command').textContent = data.command || 'No command provided';
      document.getElementById('ap-desc').textContent = data.riskReason || 'Please review this action carefully.';
      document.getElementById('ap-risk').textContent = (data.riskEmoji || '⚠️') + ' ' + (data.risk || 'unknown');

      document.getElementById('ap-sent').style.display = 'none';
      document.querySelectorAll('.approval-buttons button').forEach(b => b.disabled = false);
      document.getElementById('approval-overlay').style.display = 'flex';
    }

  async function submitApproval(decision) {
    if (!currentResumeUrl || !approvalPending) return;

    document.getElementById('ap-sent').style.display = 'block';
    document.querySelectorAll('.approval-buttons button').forEach(b => b.disabled = true);

    const resume = new URL(currentResumeUrl);
    resume.protocol = window.location.protocol;
    resume.host = window.location.host;
    const fixedUrl = resume.toString();

    try {
    const res = await fetch(fixedUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        decision,
        command: approvalData?.command,
        description: approvalData?.description,
        os: approvalData?.os,
        risk: approvalData?.risk,
        riskReason: approvalData?.riskReason,
        riskEmoji: approvalData?.riskEmoji
      })
    });

    const raw = await res.text();
    let data = null;
    try { data = JSON.parse(raw); } catch { data = { output: raw }; }

        document.getElementById('approval-overlay').style.display = 'none';
        addMessage('You ' + (decision === 'approved' ? 'approved' : 'denied') + ' the action.', 'user');

        if (data && (data.output || data.result)) {
          addMessage(data.output || data.result, 'bot');
        }
      } catch (e) {
        addMessage('Failed to send approval response.', 'bot');
      } finally {
        document.getElementById('ap-sent').style.display = 'none';
        document.querySelectorAll('.approval-buttons button').forEach(b => b.disabled = false);
        approvalPending = false;
        currentResumeUrl = null;
        approvalData = null;
        setStatus('');
        setUIBusy(false);
        input.focus();
      }
    }

    // ── Helpers ───────────────────────────────────
    function setStatus(msg) { status.textContent = msg; }

    function addMessage(text, sender) {
      const div = document.createElement('div');
      div.className = 'message ' + sender;

      // Check if it's a QuickChart image URL
      if (sender === 'bot' && text && text.startsWith('https://quickchart.io')) {
        const img = document.createElement('img');
        img.src = text;
        img.alt = 'Expense Chart';
        img.style.cssText = 'max-width:100%;border-radius:8px;margin-top:4px;';
        img.onerror = () => { div.textContent = 'Chart failed to load.'; };
        div.appendChild(img);
      } else {
        div.textContent = text;
      }

      messages.appendChild(div);
      messages.scrollTop = messages.scrollHeight;
    }

    function setUIBusy(busy) {
      input.disabled = busy;
      sendBtn.disabled = busy;
      micBtn.disabled = busy;
    }

    // ── Send text to n8n, get reply, play TTS ─────
    async function sendMessage(text) {
      if (!text.trim()) return;

      addMessage(text, 'user');
      input.value = '';
      setUIBusy(true);
      setStatus('Agent is thinking...');

      try {
        const res = await fetch(API_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ message: text })
        });

        const contentType = res.headers.get('Content-Type') || '';

        if (contentType.includes('image/')) {
          // Handle binary image response
          const blob = await res.blob();
          const imageUrl = URL.createObjectURL(blob);
          addImageMessage(imageUrl);
          setStatus('');
          return;
        }

        const raw = await res.text();

        let reply = 'No response.';
        let data = null;

        try {
          data = JSON.parse(raw);
          if (data.type === 'charts') {
            addChartsMessage(data.gainChartUrl, data.lossChartUrl);
            setStatus('');
            return;
          }

          if (data.approvalRequired) {
            approvalPending = true;
            currentResumeUrl = data.approvalUrl || null;

            if (!currentResumeUrl) {
              addMessage('Missing approval URL.', 'bot');
              approvalPending = false;
              setUIBusy(false);
              return;
            }

            showApprovalDialog(data);
            return;
          }


          reply = data.output || data.content || data.text || raw;
        } catch {
          reply = raw;
        }

        addMessage(reply, 'bot');
        setStatus('Generating audio...');

        const ttsRes = await fetch(TTS_URL + '?text=' + encodeURIComponent(reply));
        if (ttsRes.ok) {
          const audioBlob = await ttsRes.blob();
          const audioUrl = URL.createObjectURL(audioBlob);
          const audio = new Audio(audioUrl);
          audio.onended = () => URL.revokeObjectURL(audioUrl);
          await audio.play();
        }

        setStatus('');
      } catch (err) {
        console.error(err);
        setStatus('Error: ' + err.message);
      } finally {
        if (!approvalPending) {
          setUIBusy(false);
          input.focus();
        }
      }
    }

    function addImageMessage(src) {
      const div = document.createElement('div');
      div.className = 'message bot';
      const img = document.createElement('img');
      img.src = src;
      img.alt = 'Expense Chart';
      img.style.cssText = 'max-width:100%;border-radius:8px;margin-top:4px;';
      img.onload = () => { messages.scrollTop = messages.scrollHeight; };
      img.onerror = () => { div.textContent = 'Chart failed to load.'; };
      div.appendChild(img);
      messages.appendChild(div);
      messages.scrollTop = messages.scrollHeight;
    }

    function addChartsMessage(gainUrl, lossUrl) {
      const div = document.createElement('div');
      div.className = 'message bot';

      const wrap = document.createElement('div');
      wrap.style.cssText = 'display:flex;flex-direction:column;gap:12px;';

      const gainImg = document.createElement('img');
      gainImg.src = gainUrl;
      gainImg.alt = 'Gain Chart';
      gainImg.style.cssText = 'max-width:100%;border-radius:8px;';

      const lossImg = document.createElement('img');
      lossImg.src = lossUrl;
      lossImg.alt = 'Loss Chart';
      lossImg.style.cssText = 'max-width:100%;border-radius:8px;';

      wrap.appendChild(gainImg);
      wrap.appendChild(lossImg);
      div.appendChild(wrap);
      messages.appendChild(div);
      messages.scrollTop = messages.scrollHeight;
    }

    // ── Text form submit ──────────────────────────
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      sendMessage(input.value.trim());
    });

    // ── Voice recording ───────────────────────────
    let mediaRecorder = null;
    let audioChunks = [];

    micBtn.addEventListener('click', async () => {
      if (mediaRecorder && mediaRecorder.state === 'recording') {
        mediaRecorder.stop();
        return;
      }

      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaRecorder = new MediaRecorder(stream);
        audioChunks = [];

        mediaRecorder.ondataavailable = (e) => audioChunks.push(e.data);

        mediaRecorder.onstop = async () => {
          micBtn.classList.remove('recording');
          micBtn.textContent = '🎤';
          stream.getTracks().forEach(t => t.stop());

          setStatus('Transcribing...');
          setUIBusy(true);

          try {
            const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
            const formData = new FormData();
            formData.append('audio_file', audioBlob, 'recording.webm');

            const whisperRes = await fetch(WHISPER_URL, {
              method: 'POST',
              body: formData
            });
            const whisperData = await whisperRes.json();
            const transcript = whisperData.text?.trim();

            if (transcript) {
              setStatus('');
              setUIBusy(false);
              await sendMessage(transcript);
            } else {
              setStatus("Couldn't hear anything — try again.");
              setUIBusy(false);
            }
          } catch (err) {
            setStatus('Whisper error: ' + err.message);
            setUIBusy(false);
            console.error(err);
          }
        };

        mediaRecorder.start();
        micBtn.classList.add('recording');
        micBtn.textContent = '⏹';
        setStatus('Recording... click ⏹ to stop');

      } catch (err) {
        setStatus('Mic access denied: ' + err.message);
        console.error(err);
      }
    });
  </script>
</body>
</html>
`;

return { html };

// Convert the AI's text answer into a binary file object for n8n
const textContent = items[0].json.content || "";
const binaryData = Buffer.from(textContent).toString('base64');

return {
  json: { success: true },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'text/markdown',
      fileName: 'summary.md'
    }
  }
};

const rows = $input.all().map(i => i.json);

const gainTotals = {};
const lossTotals = {};

for (const row of rows) {
  const cat = row.category || 'Other';
  const amt = Math.abs(Number(row.amount) || 0);
  const isGain = row.gain === true || row.gain === 1 || row.gain === 'true';

  if (isGain) {
    gainTotals[cat] = (gainTotals[cat] || 0) + amt;
  } else {
    lossTotals[cat] = (lossTotals[cat] || 0) + amt;
  }
}

return [{
  json: {
    gainLabels: Object.keys(gainTotals),
    gainData: Object.values(gainTotals),
    lossLabels: Object.keys(lossTotals),
    lossData: Object.values(lossTotals),
  }
}];

const staticData = $getWorkflowStaticData('global');
const data = staticData.pendingApproval;

if (!data) {
  return [{ json: {} }];
}

if (!data.storedAt) {
  delete staticData.pendingApproval;
  return [{ json: {} }];
}

if (Date.now() - data.storedAt > 5 * 60 * 1000) {
  delete staticData.pendingApproval;
  return [{ json: {} }];
}

return [{ json: data }];

const stdout = $input.first().json.stdout?.trim() || "";
const stderr = $input.first().json.stderr?.trim() || "";
const error = $input.first().json.error?.trim() || "";
const code = $input.first().json.exitCode ?? 0;

const failed = !!error || code !== 0;
const output = stdout || stderr || "";

return {
  json: {
    result: failed
      ? `Command failed${code !== 0 ? ` (exit ${code})` : ""}\n${error || stderr || "No error details."}`
      : `Command executed${output ? `\n\n${output}` : ""}`
  }
};

// ── Pull data from upstream nodes ─────────────────────────────────────────
const calItems   = $("Get Today's Calendar").all();
const emailItems = $('Get Overnight Emails').all();

// ── Calendar ───────────────────────────────────────────────────────────────
const eventLines = calItems.map(i => {
  const e      = i.json;
  const title  = e.summary || '(Untitled)';
  const start  = (e.start?.dateTime || e.start?.date || '').replace('T', ' ').slice(0, 16);
  const end    = (e.end?.dateTime   || e.end?.date   || '').replace('T', ' ').slice(11, 16);
  const where  = e.location ? ` @ ${e.location}` : '';
  const status = e.status === 'tentative' ? ' ⚠️ Tentative' : '';
  return `• ${title}  [${start}${end ? '–' + end : ''}${where}]${status}`;
});
const calSection = eventLines.length
  ? eventLines.join('\n')
  : '(No calendar events today)';

// ── Emails ─────────────────────────────────────────────────────────────────
const emailLines = emailItems.map(i => {
  const e       = i.json;
  const from    = e.From    || e.from    || 'Unknown';
  const subject = e.Subject || e.subject || '(no subject)';
  const snippet = (e.snippet || '').slice(0, 160);
  return `• FROM: ${from}\n  SUBJ: ${subject}\n  …${snippet}`;
});
const emailSection = emailLines.length
  ? emailLines.join('\n\n')
  : '(No urgent or HSBC emails in the last 12 hours)';

// ── Timestamp ──────────────────────────────────────────────────────────────
const dateLabel = $now.toFormat('EEEE, MMMM d, yyyy');
const timeLabel = $now.toFormat('h:mm a');

return [{ json: { calSection, emailSection, dateLabel, timeLabel } }];

const raw  = ($input.first().json.stdout || '').trim().toLowerCase();
const task = $('Receive Msg (POST)').first().json.body.message || '';

let os = 'unknown';
if (raw.includes('darwin'))                                                   os = 'macos';
else if (raw.includes('linux'))                                               os = 'linux';
else if (raw.includes('windows') || raw.includes('mingw') || raw.includes('cygwin')) os = 'windows';

return [{ json: { detectedOS: os, task } }];

const data = $input.first().json;

// --- helpers ---
function cleanField(value) {
  if (value == null) return '';
  let v = String(value).trim();
  if ((v.startsWith('"') && v.endsWith('"')) ||
      (v.startsWith("'") && v.endsWith("'"))) {
    v = v.slice(1, -1).trim();
  }
  return v;
}

function repairJson(text) {
  // Fix missing opening quote on keys: ,description" → ,"description"
  return text.replace(/,([a-zA-Z_][a-zA-Z0-9_]*)":/g, ',"$1":');
}

function tryParse(text) {
  try { return JSON.parse(text); } catch { return null; }
}

// --- main ---
const rawOutput = data.output ?? data.text ?? data.response ?? '';
const cleaned = String(rawOutput)
  .replace(/<think>[\s\S]*?<\/think>/gi, '')
  .replace(/^```[\w]*\n?/gm, '')
  .replace(/```$/gm, '')
  .trim();

// 1. Direct parse
let parsed = tryParse(cleaned);

// 2. Repair missing opening quotes then re-parse
if (!parsed) {
  parsed = tryParse(repairJson(cleaned));
}

// 3. Extract balanced JSON block and try again
if (!parsed) {
  const start = cleaned.indexOf('{');
  if (start !== -1) {
    parsed = tryParse(repairJson(cleaned.slice(start)));
  }
}

if (!parsed) throw new Error(`Could not parse Ollama output as JSON:\n${cleaned}`);

const command     = cleanField(parsed.command);
const description = cleanField(parsed.description);
const os          = cleanField(parsed.os)?.toLowerCase();
const risk        = cleanField(parsed.risk)?.toLowerCase();
const riskReason  = cleanField(parsed.riskReason);

if (!command)     throw new Error(`Missing command field in Ollama output:\n${cleaned}`);
if (!description) throw new Error(`Missing description field in Ollama output:\n${cleaned}`);
if (!['macos','linux','windows'].includes(os))   throw new Error(`Invalid os field: ${parsed.os}`);
if (!['low','medium','high'].includes(risk))     throw new Error(`Invalid risk field: ${parsed.risk}`);
if (!riskReason)  throw new Error(`Missing riskReason field in Ollama output:\n${cleaned}`);

let finalCommand = command;
if (os === 'windows' && !/powershell(\.exe)?\s+-[Cc]ommand/i.test(finalCommand)) {
  finalCommand = `powershell -Command ${finalCommand.replace(/"/g, '`"')}`;
}

const riskEmoji = risk === 'low' ? '🟢' : risk === 'medium' ? '🟡' : '🔴';

return [{ json: { command: finalCommand, description, os, risk, riskReason, riskEmoji } }];

const data = $input.first().json;
const staticData = $getWorkflowStaticData('global');

staticData.pendingApproval = {
  approvalRequired: true,
  approvalUrl: 'http://localhost:5678/webhook/approve-command',
  command: data.command || '',
  description: data.description || '',
  risk: data.risk || '',
  riskReason: data.riskReason || '',
  riskEmoji: data.riskEmoji || '',
  os: data.os || 'unknown',
  storedAt: Date.now()
};

return [{
  json: staticData.pendingApproval
}];

const src = $input.first().json;

